### Fibonacci Sequence Generator in Java

```java
public class FibonacciGenerator {

    /**
     * Generate Fibonacci sequence up to n terms.
     * 
     * @param n number of terms to generate
     * @return Fibonacci sequence as an array
     */
    public static int[] generateFibonacci(int n) {
        if (n <= 0) {
            throw new IllegalArgumentException("n must be a positive integer");
        }

        int[] sequence = new int[n];
        sequence[0] = 0;
        sequence[1] = 1;

        for (int i = 2; i < n; i++) {
            sequence[i] = sequence[i - 1] + sequence[i - 2];
        }

        return sequence;
    }

    /**
     * Calculate the nth Fibonacci number recursively.
     * 
     * @param n index of the Fibonacci number to calculate
     * @return nth Fibonacci number
     */
    public static int fibonacciRecursive(int n) {
        if (n <= 0) {
            throw new IllegalArgumentException("n must be a positive integer");
        } else if (n == 1) {
            return 0;
        } else if (n == 2) {
            return 1;
        } else {
            return fibonacciRecursive(n - 1) + fibonacciRecursive(n - 2);
        }
    }

    public static void main(String[] args) {
        int n = 10;
        System.out.println("Fibonacci sequence up to " + n + " terms:");
        int[] sequence = generateFibonacci(n);
        for (int num : sequence) {
            System.out.print(num + " ");
        }

        System.out.println("\nNth Fibonacci number (recursive):");
        int result = fibonacciRecursive(n);
        System.out.println(result);
    }
}
