from typing import Dict, Optional

class UserProfile:
    def __init__(self, user_id: int, name: str, email: str):
        self.user_id = user_id
        self.name = name
        self.email = email

class UserRepository:
    def __init__(self):
        self.users: Dict[int, UserProfile] = {}

    def get_user(self, user_id: int) -> Optional[UserProfile]:
        try:
            return self.users[user_id]
        except KeyError:
            return None

    def add_user(self, user: UserProfile) -> None:
        self.users[user.user_id] = user

def get_user_profile(user_id: int, repository: UserRepository) -> Optional[UserProfile]:
    """
    Retrieves a user's profile by ID.

    Args:
        user_id (int): The ID of the user to retrieve.
        repository (UserRepository): The user repository to query.

    Returns:
        Optional[UserProfile]: The user's profile, or None if not found.
    """
    return repository.get_user(user_id)

# Example usage
repository = UserRepository()
repository.add_user(UserProfile(1, 'John Doe', 'john@example.com'))
print(get_user_profile(1, repository))  # Output: <UserProfile at 0x...>
print(get_user_profile(2, repository))  # Output: None
```

